import { useState } from "react";
import { Container, Row, Col, Tab, Nav, Modal, Button } from "react-bootstrap";
import { ProjectCard } from "./Projects/ProjectCard";
import projImg1 from "../assets/img/project-img1.png";
import projImg2 from "../assets/img/project-img2.png";
import projImg3 from "../assets/img/project-img3.png";
import 'animate.css';
import TrackVisibility from 'react-on-screen';
import ReactMarkdown from 'react-markdown';
import { projectsData } from "../projectsData";

export const Projects = () => {

  const [showModal, setShowModal] = useState(false);
  const [selectedProject, setSelectedProject] = useState(null);

  const handleClose = () => setShowModal(false);
  const handleShow = (project) => {
    setSelectedProject(project);
    setShowModal(true);
  };

  const projects = [
    {
      title: "IA Générative (LLM & RAG)",
      description: "Implémentation de concepts avancés en IA générative.",
      imgUrl: projImg1,
      githubUrl: "https://github.com/KamelBenstaali/Generative_AI",
      markdownContent: "### IA Générative (LLM & RAG)\n\nProjet visant à implémenter des solutions d'Intelligence Artificielle générative en utilisant des architectures avancées comme RAG (Retrieval-Augmented Generation) pour améliorer les performances des LLM sur des données spécifiques."
    },
    {
      title: "Chatbot IA & Audio/SQL",
      description: "Assistants intelligents intégrés à des bases de données et des flux audio.",
      imgUrl: projImg2,
      githubUrl: "https://github.com/KamelBenstaali/BABot_SQL",
      markdownContent: "### Chatbot IA & Audio/SQL\n\nCréation d'agents conversationnels interactifs capables d'interroger directement des bases de données SQL ou d'analyser des flux audio pour extraire des informations métier."
    },
    {
      title: "Machine Learning Projects",
      description: "Projets variés d'analyse de données et de modèles ML classiques.",
      imgUrl: projImg3,
      githubUrl: "https://github.com/KamelBenstaali/ML_Projects",
      markdownContent: "### Machine Learning Projects\n\nCe dépôt regroupe plusieurs expérimentations sur des modèles de Machine Learning classiques (Régression, Classification, Random Forest) appliqués à des jeux de données variés."
    }
  ];

  return (
    <section className="project" id="projects">
      <Container>
        <Row>
          <Col size={12}>
            <TrackVisibility>
              {({ isVisible }) =>
              <div className={isVisible ? "animate__animated animate__fadeIn": ""}>
                <h2>Mes Projets</h2>
                <p>Découvrez une sélection de mes travaux en Intelligence Artificielle, séparés en projets phares et projets académiques.</p>
                <Tab.Container id="projects-tabs" defaultActiveKey="first">
                  <Nav variant="pills" className="nav-pills mb-5 justify-content-center align-items-center" id="pills-tab">
                    <Nav.Item>
                      <Nav.Link eventKey="first">Projets Phares</Nav.Link>
                    </Nav.Item>
                    <Nav.Item>
                      <Nav.Link eventKey="second">Projets Académiques</Nav.Link>
                    </Nav.Item>
                  </Nav>
                  <Tab.Content id="slideInUp" className={isVisible ? "animate__animated animate__slideInUp" : ""}>
                    <Tab.Pane eventKey="first">
                      <Row>
                        {
                          projects.map((project, index) => {
                            return (
                              <ProjectCard
                                key={index}
                                {...project}
                                onClick={() => handleShow(project)}
                                />
                            )
                          })
                        }
                      </Row>
                    </Tab.Pane>
                    <Tab.Pane eventKey="second">
                      <Row>
                        {
                          projectsData.map((project, index) => {
                            return (
                              <ProjectCard
                                key={index}
                                {...project}
                                onClick={() => handleShow(project)}
                                />
                            )
                          })
                        }
                      </Row>
                    </Tab.Pane>
                  </Tab.Content>
                </Tab.Container>
              </div>}
            </TrackVisibility>
          </Col>
        </Row>
      </Container>

      {/* Modal Project Detail */}
      <Modal show={showModal} onHide={handleClose} size="lg" centered>
        <Modal.Header closeButton className="bg-dark text-white border-bottom-0">
          <Modal.Title>{selectedProject?.title}</Modal.Title>
        </Modal.Header>
        <Modal.Body className="bg-dark text-white custom-modal-body" style={{ maxHeight: '70vh', overflowY: 'auto' }}>
          {selectedProject?.markdownContent ? (
            <ReactMarkdown>{selectedProject.markdownContent}</ReactMarkdown>
          ) : (
            <p>{selectedProject?.description}</p>
          )}
        </Modal.Body>
        <Modal.Footer className="bg-dark border-top-0">
          {selectedProject?.githubUrl && (
            <Button variant="outline-light" href={selectedProject.githubUrl} target="_blank">
              Voir sur GitHub
            </Button>
          )}
          <Button variant="secondary" onClick={handleClose}>
            Fermer
          </Button>
        </Modal.Footer>
      </Modal>

    </section>
  )
}
